class Solution:
    def countPalindromicSubsequences(self, s):
        MOD = 10 ** 9 + 7
        n = len(s)
        if n == 0:
            return 0
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(10000)
        @lru_cache(maxsize=None)
        def count(i, j):
            if i > j:
                return 0
            total = 0
            for c in 'abcd':
                lo = -1
                hi = -1
                for k in range(i, j + 1):
                    if s[k] == c:
                        if lo == -1:
                            lo = k
                        hi = k
                if lo == -1:
                    continue
                if lo == hi:
                    total += 1
                else:
                    total += 2 + count(lo + 1, hi - 1)
            return total % MOD
        return count(0, n - 1) % MOD

